{"content": "     1|import React, { useState } from 'react'
     2|import { useRouter } from 'next/router'
     3|
     4|interface NavItem {
     5|  label: string
     6|  href?: string
     7|  children?: NavItem[]
     8|}
     9|
    10|const LOCALE_FLAGS: Record<string, string> = {
    11|  es: '🇪🇸 ES',
    12|  en: '🇬🇧 EN',
    13|  nl: '🇳🇱 NL',
    14|  de: '🇩🇪 DE',
    15|}
    16|
    17|export function Header({ navigation, locale }: { navigation: any; locale?: string }) {
    18|  const [open, setOpen] = useState(false)
    19|  const [langOpen, setLangOpen] = useState(false)
    20|  const navItems: NavItem[] = navigation?.navItems || []
    21|  const router = useRouter()
    22|  const currentLocale = locale || 'es'
    23|
    24|  function switchLocale(newLocale: string) {
    25|    // Get current path without locale prefix
    26|    const path = router.asPath
    27|    const parts = path.split('/').filter(Boolean)
    28|    const LOCALES = ['es', 'en', 'nl', 'de']
    29|    let cleanPath = path
    30|    if (parts.length > 0 && LOCALES.includes(parts[0])) {
    31|      cleanPath = '/' + parts.slice(1).join('/') || '/'
    32|    }
    33|    const newPath = '/' + newLocale + cleanPath
    34|    // Redirect through Next.js router (also sets cookie via getServerSideProps)
    35|    window.location.href = newPath
    36|  }
    37|
    38|  return (
    39|    <header style={{ background: 'rgba(255,255,255,0.92)', backdropFilter: 'blur(12px)', WebkitBackdropFilter: 'blur(12px)', borderBottom: '1px solid rgba(0,0,0,0.05)', boxShadow: '0 1px 3px rgba(0,0,0,0.04)', position: 'sticky', top: 0, zIndex: 100 }}>
    40|      <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '0.75rem 1rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
    41|        <a href="/" style={{ display: 'flex', alignItems: 'center', textDecoration: 'none' }}>
    42|          <img src="/images/brand/logo.svg" alt="Nexa Paraguay" style={{ height: '36px', width: 'auto' }} />
    43|        </a>
    44|        <button onClick={() => setOpen(!open)} style={{ display: 'none', background: 'none', border: 'none', fontSize: '1.5rem', cursor: 'pointer', padding: '0.25rem', color: '#1B2A4A' }}>
    45|          {open ? '✕' : '☰'}
    46|        </button>
    47|        <nav style={{ display: 'flex', gap: '1.5rem', alignItems: 'center' }}>
    48|          {navItems.map((item, i) => (
    49|            <div key={i} style={{ position: 'relative' }}>
    50|              {(() => {
    51|                let href = item.href || '#'
    52|                // Strip existing multiclient prefix (/s/en/nexa-paraguay/)
    53|                href = href.replace(/^\/s\/[^/]+\/[^/]+/, '')
    54|                // Prepend locale prefix for internal links
    55|                if (!href.startsWith('http') && !href.startsWith('/' + currentLocale)) {
    56|                  href = '/' + currentLocale + href
    57|                }
    58|                return <a href={href} style={{ color: '#333', textDecoration: 'none', fontWeight: 500, fontSize: '0.9rem', padding: '0.25rem 0', borderBottom: item.children ? '1px dashed #ccc' : 'none' }}>
    59|                  {item.label}
    60|                </a>
    61|              })()}
    62|            </div>
    63|          ))}
    64|          {/* Language Switcher Dropdown */}
    65|          <div style={{ position: 'relative' }}>
    66|            <button
    67|              onClick={() => setLangOpen(!langOpen)}
    68|              style={{ background: '#F5F5F0', border: '1px solid #ddd', borderRadius: '6px', padding: '0.3rem 0.6rem', cursor: 'pointer', fontSize: '0.85rem', color: '#333', display: 'flex', alignItems: 'center', gap: '0.3rem' }}
    69|              aria-label="Switch language"
    70|            >
    71|              {LOCALE_FLAGS[currentLocale] || '🌐 ES'}
    72|              <span style={{ fontSize: '0.7rem' }}>{langOpen ? '▲' : '▼'}</span>
    73|            </button>
    74|            {langOpen && (
    75|              <div style={{ position: 'absolute', top: '100%', right: 0, marginTop: '0.3rem', background: '#fff', border: '1px solid #ddd', borderRadius: '8px', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', zIndex: 200, minWidth: '100px' }}>
    76|                {Object.entries(LOCALE_FLAGS).map(([code, label]) => (
    77|                  <button
    78|                    key={code}
    79|                    onClick={() => { setLangOpen(false); switchLocale(code); }}
    80|                    style={{ display: 'block', width: '100%', padding: '0.5rem 0.75rem', textAlign: 'left', background: code === currentLocale ? '#F5F5F0' : 'transparent', border: 'none', cursor: 'pointer', fontSize: '0.85rem', color: '#333', fontWeight: code === currentLocale ? 700 : 400 }}
    81|                  >
    82|                    {label}
    83|                  </button>
    84|                ))}
    85|              </div>
